using sv_21d9af8280f6436ba8588b8a1739373d.Models;

namespace sv_21d9af8280f6436ba8588b8a1739373d.Services;

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

using sv_21d9af8280f6436ba8588b8a1739373d.Models;

namespace sv_21d9af8280f6436ba8588b8a1739373d.Services;

public sealed class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> SeedData = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Spaghetti Carbonara", "Classic Roman pasta with eggs, pecorino, guanciale, and black pepper.", 30),
            new(2, "Margherita Pizza", "Neapolitan pizza with San Marzano tomatoes, mozzarella, and fresh basil.", 45),
            new(3, "Tiramisu", "Layered coffee-soaked ladyfingers with mascarpone cream and cocoa.", 40),
        },
        [2] = new List<Recipe>
        {
            new(4, "Chicken Tikka Masala", "Grilled chicken in a creamy spiced tomato sauce served with rice.", 50),
            new(5, "Palak Paneer", "Fresh spinach cooked with paneer cubes in aromatic spices.", 35),
            new(6, "Butter Naan", "Soft leavened flatbread brushed with butter, baked in a tandoor.", 25),
        },
        [3] = new List<Recipe>
        {
            new(7, "Tacos al Pastor", "Marinated pork tacos with pineapple, onion, and cilantro.", 60),
            new(8, "Guacamole", "Fresh avocado dip with lime, cilantro, jalapeño, and tomato.", 10),
            new(9, "Churros", "Fried dough pastry coated in cinnamon sugar, served with chocolate sauce.", 30),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        return SeedData.TryGetValue(cuisineId, out var recipes)
            ? recipes
            : new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@using sv_21d9af8280f6436ba8588b8a1739373d.Models
@using sv_21d9af8280f6436ba8588b8a1739373d.Services
@implements IDisposable
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger
@inject NavigationManager Navigation

<PageTitle>Recipes</PageTitle>

<h1>Recipes — Cuisine @CuisineId</h1>

@if (_errorMessage is not null)
{
    <div class="alert alert-danger d-flex justify-content-between align-items-center" role="alert">
        <span>@_errorMessage</span>
        <button class="btn btn-outline-danger btn-sm" @onclick="RetryAsync">Retry</button>
    </div>
}

@if (_recipes is null && _errorMessage is null)
{
    <div class="d-flex align-items-center gap-2 my-4">
        <div class="spinner-border spinner-border-sm" role="status"></div>
        <span>Loading recipes…</span>
    </div>
}
else if (_recipes is not null)
{
    @if (_isRefreshing)
    {
        <div class="d-flex align-items-center gap-2 mb-3 text-muted">
            <div class="spinner-border spinner-border-sm" role="status"></div>
            <small>Refreshing…</small>
        </div>
    }

    @if (DisplayedRecipes.Count == 0)
    {
        <p class="text-muted">No recipes found for this cuisine.</p>
    }
    else
    {
        <div class="row row-cols-1 row-cols-md-3 g-4">
            @foreach (var recipe in DisplayedRecipes)
            {
                <div class="col">
                    <div class="card h-100">
                        <div class="card-body">
                            <h5 class="card-title">@recipe.Title</h5>
                            <p class="card-text">@recipe.Description</p>
                        </div>
                        <div class="card-footer text-muted">
                            Prep time: @recipe.PrepTimeMinutes min
                        </div>
                    </div>
                </div>
            }
        </div>
    }
}

@code {
    private List<Recipe>? _recipes;
    private bool _isRefreshing;
    private string? _errorMessage;
    private int _loadedCuisineId;
    private CancellationTokenSource? _cts;

    [Parameter]
    public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private List<Recipe> DisplayedRecipes
    {
        get
        {
            if (_recipes is null)
                return new List<Recipe>();

            return string.Equals(Sort, "popular", StringComparison.OrdinalIgnoreCase)
                ? _recipes.OrderByDescending(r => r.PrepTimeMinutes).ToList()
                : _recipes.OrderByDescending(r => r.Id).ToList();
        }
    }

    protected override Task OnParametersSetAsync()
    {
        if (CuisineId != _loadedCuisineId)
        {
            return LoadRecipesAsync();
        }

        // Sort changed — no reload needed, just re-render.
        return Task.CompletedTask;
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight request for a previous cuisine.
        CancelPending();

        _errorMessage = null;
        _isRefreshing = _recipes is not null;
        _loadedCuisineId = CuisineId;

        var cts = new CancellationTokenSource();
        _cts = cts;

        try
        {
            var results = await RecipeService.GetByCuisineAsync(CuisineId, cts.Token);

            // Only apply results if this request wasn't superseded.
            if (!cts.Token.IsCancellationRequested)
            {
                _recipes = results;
                _isRefreshing = false;
            }
        }
        catch (OperationCanceledException)
        {
            // Expected when the user navigated to a different cuisine or left the page.
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout fetching recipes for cuisine {CuisineId}", CuisineId);
            _isRefreshing = false;
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error fetching recipes for cuisine {CuisineId}", CuisineId);
            _isRefreshing = false;
            _errorMessage = "Something went wrong while loading recipes. Please try again.";
        }
    }

    private async Task RetryAsync()
    {
        await LoadRecipesAsync();
    }

    private void CancelPending()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }

    public void Dispose()
    {
        CancelPending();
    }
}

